mapper.select:
SELECT
distinct t.*,
t1.name dept_name,
t1.parents dept_parents,
t2.name post_name
FROM
castle_sys_user t
left outer join castle_sys_dept t1 on t.dept_id  = t1.id
LEFT OUTER JOIN castle_sys_post t2 ON t.post_id = t2.id
WHERE
t.is_deleted = 2

    and t.login_name = #{sysUserDto.loginName}


    and t.real_name like concat('%',#{sysUserDto.realName},'%')


    and t.phone = #{sysUserDto.phone}


    and t.dept_id = #{sysUserDto.deptId}


    and (t.dept_id in

        #{id}


        or t.id = #{createUserLimit}


        or t.post_id in

            #{id}


    )


    and (t.post_id in

        #{id}


        or t.id = #{createUserLimit}

    )


    and t.id = #{createUserLimit}

order by create_time desc

    limit #{map.offset},#{map.rows}

