select.if:
select  user.*
from (
select t1.*,
#                 t1.parent_id,
if(find_in_set(parent_id, @parentId) > 0 or find_in_set(id, @parentId) > 0 , @parentId := concat(@parentId, ',', id), 0) as ischild
from (
select  *
from castle_sys_dept t
where is_deleted=2
) t1,
(select @parentId := (SELECT  group_concat(distinct t1.dept_id ) FROM castle_sys_role_data_auth t1 WHERE t1.role_id IN

    #{item}

)) t2
) t3  join castle_sys_user user on user.dept_id=t3.id
where ischild != 0

    and user.real_name like concat('%',#{realName},'%')


    limit #{map.offset},#{map.rows}

select user.* from castle_sys_dept t join castle_sys_user user on user.dept_id=t.id where t.is_deleted = 2
and user.real_name like concat('%',#{realName},'%')
limit #{map.offset},#{map.rows}

